#include <iostream>
#include <string>

class Device {
protected:
    std::string brand;
public:
    Device(const std::string& b) : brand(b) {
        std::cout << "[Device] Constructor: " << brand << "\n";
    }
    ~Device() {
        std::cout << "[Device] Destructor\n";
    }
};

class Computer : public Device {
protected:
    int ram_gb;
public:
    Computer(const std::string& b, int r) : Device(b), ram_gb(r) {
        std::cout << "[Computer] Constructor: " << ram_gb << "GB\n";
    }
    ~Computer() {
        std::cout << "[Computer] Destructor\n";
    }
};

class Laptop : public Computer {
private:
    double screen_size;
public:
    Laptop(const std::string& b, int r, double s) : Computer(b, r), screen_size(s) {
        std::cout << "[Laptop] Constructor: " << screen_size << " inches\n";
    }
    ~Laptop() {
        std::cout << "[Laptop] Destructor\n";
    }
    void show_info() const {
        std::cout << "Specs: " << brand << " laptop with " << ram_gb << "GB RAM\n";
    }
};

int main() {
    {
        Laptop my_laptop("Amdahl", 16, 14.0);
        my_laptop.show_info();
    }
    return 0;
}

code_example_2_practical.code:
#include <iostream>
#include <string>
#include <vector>
#include <memory>

class UIElement {
protected:
    int x, y;
public:
    UIElement(int px, int py) : x(px), y(py) {
        std::cout << "UIElement built at (" << x << ", " << y << ")\n";
    }
    virtual ~UIElement() = default;
    virtual void draw() const = 0;
};

class Interactive {
protected:
    bool is_focused = false;
public:
    Interactive() {
        std::cout << "Interactive focus states initialized\n";
    }
    void toggle_focus() {
        is_focused = !is_focused;
        std::cout << "Focus state toggled to: " << (is_focused ? "True" : "False") << "\n";
    }
    virtual ~Interactive() = default;
};

class Button : public UIElement, public Interactive {
private:
    std::string text;
public:
    Button(int px, int py, std::string label) 
        : UIElement(px, py), Interactive(), text(std::move(label)) {
        std::cout << "Button '" << text << "' fully created\n";
    }
    void draw() const override {
        std::cout << "Button ['" << text << "'] displayed at (" << x << ", " << y << ")";
        if (is_focused) {
            std::cout << " <Focused>";
        }
        std::cout << "\n";
    }
    ~Button() override {
        std::cout << "Button '" << text << "' layout destroyed\n";
    }
};

int main() {
    std::unique_ptr<UIElement> element = std::make_unique<Button>(100, 200, "Click Me");
    element->draw();

    Button* raw_btn = dynamic_cast<Button*>(element.get());
    if (raw_btn) {
        raw_btn->toggle_focus();
    }
    element->draw();
    return 0;
}

